// MRN, MSN 입력 -> 대문자 변환, grid mrn
scwin.capitalMask = function (value) {
    var filteredVal = value.replace(/[ㄱ-ㅎㅏ-ㅣ가-힣]/g, '');  // 한글만 제거
    return filteredVal.toUpperCase();
}

// 수신업체 구분 value 포맷 변경 
scwin.sbFormat = function(value) {
    if (value.trim() === "선택" || value === ":") {
        return ":";
    } else {
        return value;
    }

}
